// ─────────────────────────────────────────────────────────────
// EDIT ME: your RSS feed sources.
// Add one entry per feed you want in your digest.
// `source` is a friendly label shown in the email; `url` is the feed.
// The next node (RSS Read) runs ONCE PER ITEM returned here.
// ─────────────────────────────────────────────────────────────
const FEEDS = [
  { source: 'TechCrunch',     url: 'https://techcrunch.com/feed/' },
  { source: 'The Verge',      url: 'https://www.theverge.com/rss/index.xml' },
  { source: 'Hacker News',    url: 'https://hnrss.org/frontpage' },
];

return FEEDS.map((feed) => ({ json: feed }));

// Combine every article from every feed, keep only recent ones,
// rank newest-first, take the top N, and build a compact text block
// that the AI can summarize cheaply.

const LOOKBACK_DAYS = 7;   // only keep articles newer than this
const MAX_ARTICLES  = 15;  // cap to control token cost

const cutoff = Date.now() - LOOKBACK_DAYS * 24 * 60 * 60 * 1000;

const stripHtml = (s) => String(s || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

const seen = new Set();
const articles = [];

for (const item of $input.all()) {
  const a = item.json || {};
  const title = stripHtml(a.title);
  const link = a.link || a.guid || '';
  if (!title || !link) continue;

  // Dedupe by link, then by lowercased title
  const key = String(link).split('?')[0].toLowerCase();
  const titleKey = title.toLowerCase();
  if (seen.has(key) || seen.has(titleKey)) continue;
  seen.add(key);
  seen.add(titleKey);

  // Parse publish date; if missing/invalid, keep the article (treat as 'now')
  const raw = a.isoDate || a.pubDate || a.published || a.date;
  const ts = raw ? Date.parse(raw) : NaN;
  const ms = Number.isNaN(ts) ? Date.now() : ts;
  if (!Number.isNaN(ts) && ms < cutoff) continue;

  const source = a.source || a.creator || (a.meta && a.meta.title) || 'Source';
  const snippet = stripHtml(a.contentSnippet || a.content || a.summary || a.description).slice(0, 220);

  articles.push({ title, link, source, snippet, ms });
}

articles.sort((x, y) => y.ms - x.ms);
const top = articles.slice(0, MAX_ARTICLES);

const articlesText = top
  .map((a, i) => `${i + 1}. ${a.title} — ${a.source} — ${a.link}\n   ${a.snippet}`)
  .join('\n\n');

return [{
  json: {
    articleCount: top.length,
    generatedFor: new Date().toISOString().slice(0, 10),
    articlesText: articlesText || 'No new articles were found in the lookback window.',
  },
}];
